const body = msg.payload;
if (!body || !Array.isArray(body.ac)) {
    node.warn('ADSB.lol: empty or invalid response');
    return null;
}

const FT_TO_M = 0.3048;
const KT_TO_MPS = 0.514444;

function feature(a) {
    if (a.lat == null || a.lon == null) return null;
    const hex = (a.hex || '').trim();
    const reg = a.r || '';
    const acType = a.t || '';
    const squawk = a.squawk || '';
    const callsign = ((a.flight || '').trim()) || reg || hex || 'AIR';
    const altFt = a.alt_geom != null ? a.alt_geom
                : a.alt_baro != null ? a.alt_baro
                : 0;
    const altM = altFt * FT_TO_M;
    const speedKt = a.gs != null ? a.gs : 0;
    const speedMps = speedKt * KT_TO_MPS;
    const track = a.track != null ? a.track
                : a.true_heading != null ? a.true_heading
                : a.mag_heading != null ? a.mag_heading
                : 0;
    return {
        type: 'Feature',
        id: hex,
        geometry: { type: 'Point', coordinates: [a.lon, a.lat, altM] },
        properties: {
            callsign,
            remarks: `ICAO ${hex} | ${reg} ${acType} | ${Math.round(altFt)} ft | ${Math.round(speedKt)} kt | hdg ${Math.round(track)}° | sq ${squawk}`.replace(/\s+/g, ' ').trim(),
            altitude: altM,
            speed: speedMps,
            course: track
        }
    };
}

const features = body.ac.map(feature).filter(f => f != null);
msg.payload = { type: 'FeatureCollection', features };
return msg;
